const body = $input.first().json.body || {};
const prompt = body.prompt || 'a beautiful landscape';
const aspectRatio = body.aspect_ratio || '1:1';
const quality = body.quality || '1k';
const modelChoice = body.model || 'nano-banana-pro';
const refBase64 = body.refImageBase64 || null;
const refMime = body.refImageMime || null;

// Map model names to actual Gemini model IDs
const modelMap = {
  'nano-banana-pro': 'gemini-3.1-flash-image-preview',
  'nano-banana-2': 'gemini-3.1-flash-image-preview',
};
const geminiModel = modelMap[modelChoice] || 'gemini-3.1-flash-image-preview';

// Map aspect ratio to description
const arMap = {
  '1:1': 'square format (1:1 aspect ratio)',
  '9:16': 'vertical portrait format (9:16 aspect ratio, taller than wide)',
  '16:9': 'horizontal landscape format (16:9 aspect ratio, wider than tall)',
  '4:3': '4:3 aspect ratio format',
  '3:4': 'portrait 3:4 aspect ratio format',
  '3:2': '3:2 aspect ratio format',
  '2:3': 'portrait 2:3 aspect ratio format'
};
const arDesc = arMap[aspectRatio] || aspectRatio + ' aspect ratio';

// Build parts array
const parts = [];

// Add reference image if provided
if (refBase64 && refMime) {
  parts.push({ inlineData: { mimeType: refMime, data: refBase64 } });
  parts.push({ text: `Generate an image in ${arDesc}. Use the provided reference image as visual guidance for style, composition, subject, or setting.\n\n${prompt}` });
} else {
  parts.push({ text: `Generate an image in ${arDesc}.\n\n${prompt}` });
}

const requestBody = {
  contents: [{ parts: parts }],
  generationConfig: {
    responseModalities: ['IMAGE', 'TEXT'],
    temperature: 1,
    maxOutputTokens: 8192
  }
};

return [{ json: { requestBody, geminiModel, prompt, aspectRatio, quality } }];

const data = $input.first().json;

// Check for HTTP error
if (data.error) {
  return [{ json: { 
    success: false, 
    error: data.error.message || 'Gemini API error',
    code: data.error.code || 500
  }}];
}

const candidates = data.candidates || [];
if (candidates.length > 0) {
  const parts = candidates[0].content?.parts || [];

  for (const part of parts) {
    if (part.inlineData) {
      const mimeType = part.inlineData.mimeType || 'image/png';
      const base64Data = part.inlineData.data;
      const dataUrl = `data:${mimeType};base64,${base64Data}`;

      return [{ json: { 
        success: true, 
        imageUrl: dataUrl,
        mimeType: mimeType,
        size: Math.round(base64Data.length / 1024) + 'KB'
      }}];
    }
  }

  for (const part of parts) {
    if (part.text) {
      return [{ json: { 
        success: false, 
        error: 'Gemini chỉ trả text, không tạo được ảnh. Thử prompt khác.',
        text: part.text.substring(0, 500)
      }}];
    }
  }
}

if (data.promptFeedback?.blockReason) {
  return [{ json: { 
    success: false, 
    error: 'Prompt bị chặn bởi Safety: ' + data.promptFeedback.blockReason
  }}];
}

return [{ json: { success: false, error: 'Không có ảnh trong response' } }];
